```csharp
using System;
using System.Collections.Generic;
using System.Linq;

public class LaptopFilter
{
    public static void Main(string[] args)
    {
        // Assuming you have a List<Laptop> called laptops
        List<Laptop> laptops = new List<Laptop>();

        // Add laptops to the list (omitted for brevity)

        // Filter laptops based on the given criteria
        var filteredLaptops = FilterLaptops(laptops);

        // Display the filtered laptops
        foreach (var laptop in filteredLaptops)
        {
            Console.WriteLine($"Processor: {laptop.Processor}, RAM: {laptop.RAM}GB, Storage: {laptop.Storage}GB, Battery Life: {laptop.BatteryLife} hours, Screen Size: {laptop.ScreenSize}\", Graphics Card: {laptop.GraphicsCard}");
        }
    }

    private static IEnumerable<Laptop> FilterLaptops(List<Laptop> laptops)
    {
        // Use LINQ to filter the laptops based on the criteria
        return laptops.Where(laptop => 
            laptop.Processor.Contains("Intel Core i5") || laptop.Processor.Contains("Intel Core i7") || laptop.Processor.Contains("AMD Ryzen 5") || laptop.Processor.Contains("AMD Ryzen 7") ||
            laptop.RAM >= 8 &&
            laptop.Storage >= 256 &&
            laptop.BatteryLife >= 8 &&
            laptop.ScreenSize >= 13 &&
            (laptop.GraphicsCard.Contains("Dedicated") || laptop.GraphicsCard.Contains("Integrated"))
        );
    }
}
```

This code defines a `FilterLaptops` method that takes a list of `Laptop` objects and returns a filtered list of laptops that meet the specified criteria. The LINQ `Where` method is used to filter the laptops based on the given conditions.

